mapper.select:
SELECT a.year AS `year`, COUNT(*) AS count FROM teacher_archive a WHERE a.deleted = 0 AND a.status = 1
AND a.teacher_id = #{teacherId}
GROUP BY a.year ORDER BY a.year

SELECT t.type_name AS `type`, COUNT(*) AS count FROM teacher_archive a LEFT JOIN archive_type t ON a.type_id = t.type_id AND t.deleted = 0 WHERE a.deleted = 0 AND a.status = 1
AND a.teacher_id = #{teacherId}
GROUP BY a.type_id, t.type_name
